<style lang="scss" scoped>
.ziti-tip {
  border: 1px solid #7db3f2;
  border-radius: 4px;
  color: #0d4888;
  padding: 4px 6px;
  background-color: #e6f0ff;
  font-size: 12px;
}
.action-container {
  margin-bottom: 0;
  margin-top: 10px;
}
</style>
<template>
  <div class="ziti-list">
    <div class="ziti-tip">
      一個自提點僅可被一個店鋪綁定使用；每個店鋪可綁定多個自提點，綁定至同一店鋪的自提點共享該店鋪庫存。
    </div>
    <div class="action-container">
      <el-button type="primary" @click="createZitiAddress"> 新增自提點 </el-button>
    </div>

    <SpFilterForm :model="formData" @onSearch="onSearch" @onReset="onSearch">
      <SpFilterFormItem prop="region" label="自提點地址:">
        <el-cascader
          ref="region"
          v-model="formData.region"
          filterable
          clearable
          placeholder="選擇地區篩選"
          :options="district"
        />
      </SpFilterFormItem>
      <SpFilterFormItem prop="keywords" label="自提點名稱:">
        <el-input v-model="formData.keywords" placeholder="自提點名稱關鍵詞" />
      </SpFilterFormItem>
    </SpFilterForm>
    <SpFinder
      ref="finder"
      no-selection
      :setting="setting"
      :hooks="{
        beforeSearch: beforeSearch
      }"
      url="/pickuplocation/list"
    />
  </div>
</template>

<script>
import { createSetting } from '@shopex/finder'
import district from '@/common/district.json'
import { getRegionNameById, VERSION_PLATFORM, IS_ADMIN, IS_DISTRIBUTOR } from '@/utils'
export default {
  name: 'ZitiList',
  data() {
    return {
      formData: {
        region: [],
        keywords: ''
      },
      district,
      setting: createSetting({
        actions: [
          {
            name: '編輯',
            key: 'detail',
            type: 'button',
            buttonType: 'text',
            action: {
              handler: ([row]) => {
                this.$router.push({
                  path: IS_DISTRIBUTOR ? `/shopadmin/order/logistics/addziti/${row.id}`:`/order/entitytrade/logistics/addziti/${row.id}`
                })
              }
            }
          },
          {
            name: '刪除',
            key: 'apply',
            type: 'button',
            buttonType: 'text',
            action: {
              handler: async ([row]) => {
                await this.$confirm(`確認刪除？`, '提示', {
                  confirmButtonText: '確定',
                  cancelButtonText: '取消'
                })
                await this.$api.pickuplocation.deleteZitiLocation(row.id)
                this.$refs['finder'].refresh()
              }
            }
          }
        ],
        columns: [
          { name: '自提點名稱', key: 'name' },
          {
            name: '地址',
            render: (h, { row }) =>
              h('span', {}, `${row.province}${row.city}${row.area}${row.address}`)
          },
          {
            name: '聯係電話',
            key: 'contract_phone'
          },
          {
            name: '綁定店鋪',
            key: 'rel_distributor_name',
            render: (h, { row }) => {
              return (
                <div>
                  <span>{row.rel_distributor_name || ''}</span>
                  {/* {!row.rel_distributor_name && ( */}
                  <el-button
                    slot='reference'
                    type='text'
                    onClick={this.onSelectStore.bind(this, row)}
                  >
                    <i class='el-icon-edit' />
                  </el-button>
                  {/* )} */}
                </div>
              )
            }
          }
        ]
      })
    }
  },
  created() {},
  mounted() {
    this.$EventBus.$on('event.zitilist.refresh', () => {
      this.$refs['finder'].refresh()
    })
  },
  methods: {
    beforeSearch(params) {
      const { region } = this.formData
      const [province, city, area] = getRegionNameById(region, district)
      const _params = {
        ...params,
        name: this.formData.keywords,
        province: province,
        city: city,
        area: area
      }

      return _params
    },
    onSearch() {
      this.$refs['finder'].refresh()
    },
    createZitiAddress() {
      const url = IS_DISTRIBUTOR
        ? '/shopadmin/order/logistics/addziti'
        : '/order/entitytrade/logistics/addziti'
      this.$router.push({
        path: url
      })
    },
    onShowPopover() {},
    onBindStore() {},
    async onSelectStore({ id, rel_distributor_id }) {
      let params = {
        data: [rel_distributor_id],
        multiple: false
      }
      if (VERSION_PLATFORM && IS_ADMIN) {
        params = {
          ...params,
          distribution_type: 0
        }
      }
      const { data } = await this.$picker.shop(params)
      if (data.length > 0) {
        const [distributor] = data
        const { distributor_id } = distributor
        distributor_id
        await this.$api.pickuplocation.bindZitiLocation({
          id,
          rel_distributor_id: distributor_id
        })
        this.$refs['finder'].refresh()
      }
    }
  }
}
</script>
